import React, { useState } from "react";
import "../styles/dashboard.css";

const LabourDashboard = () => {
  const [status, setStatus] = useState("Available");

  const jobs = [
    { id: 1, title: "House Wiring", pay: "₹500/day", location: "Mysore" },
    { id: 2, title: "Fan Repair", pay: "₹300/day", location: "Nearby" }
  ];

  return (
    <div className="dashboard-container">

      {/* TOPBAR */}
      <div className="topbar">
        <h3>Labour Dashboard</h3>

        <button className="btn-outline">Logout</button>
      </div>

      <div className="grid grid-2">

        {/* PROFILE */}
        <div className="card">
          <h4>Profile</h4>
          <p>Electrician</p>

          <button
            className="btn-green"
            onClick={() =>
              setStatus(status === "Available" ? "Busy" : "Available")
            }
          >
            Status: {status}
          </button>
        </div>

        {/* EARNINGS */}
        <div className="card">
          <h4>Earnings</h4>
          <h2>₹12,500</h2>
          <p style={{ color: "#6b7280" }}>This month</p>
        </div>

        {/* JOBS */}
        <div className="card full">

          <h4>Available Jobs</h4>

          {jobs.map((job) => (
            <div key={job.id} className="card" style={{ marginTop: "12px" }}>
              <h5>{job.title}</h5>
              <p>{job.location}</p>
              <p>{job.pay}</p>

              <button className="btn-green">Accept</button>
              <button className="btn-red" style={{ marginLeft: "10px" }}>
                Reject
              </button>
            </div>
          ))}

        </div>

      </div>

    </div>
  );
};

export default LabourDashboard;
